//! `--squash SOURCE,TARGET` — pick the `jj squash --from/--into`
//! revision pair (e.g. `@,@-`). See [options_flags](README.md) for
//! shared architecture.

use clap::Args;

/// Parsed `--squash` value: the source and target revisions.
///
/// - Produced by [`SquashSpec::parse`] (also wired as the leaf's
///   `value_parser`, so clap rejects malformed input at parse time).
/// - Both halves are guaranteed non-empty.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SquashSpec {
    pub source: String,
    pub target: String,
}

impl SquashSpec {
    /// Parse a `SOURCE,TARGET` pair (e.g. `@,@-`); both halves
    /// must be non-empty.
    pub fn parse(s: &str) -> Result<Self, String> {
        let parts: Vec<&str> = s.split(',').collect();
        if parts.len() != 2 || parts[0].is_empty() || parts[1].is_empty() {
            return Err(format!(
                "invalid --squash value '{s}': expected SOURCE,TARGET (e.g. @,@-)"
            ));
        }
        Ok(SquashSpec {
            source: parts[0].to_string(),
            target: parts[1].to_string(),
        })
    }
}

/// `OptionParser` impl for `--squash` (non-boolean domain).
/// Documentation-level — consumers can use either
/// `SquashSpec::parse` directly or `SquashSpecParser::parse`.
pub struct SquashSpecParser;

impl super::OptionParser for SquashSpecParser {
    type Value = SquashSpec;

    fn parse(s: &str) -> Result<Self::Value, String> {
        SquashSpec::parse(s)
    }
}

/// `--squash` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
///
/// - The single field is named `value` (the parsed value-side of
///   the option); the flag name comes from `#[arg(long = "squash")]`,
///   so the consumer reads `args.<leaf>.value` rather than doubling
///   the flag name.
/// - Bare `--squash` (no value) defaults to `@,@-`.
/// - `num_args = 0..=1` so the value form `--squash @,@-` also
///   works without quoting.
#[derive(Args, Debug, Clone, Default)]
pub struct SquashOption {
    /// Squash SOURCE into TARGET [default: @,@-]
    #[arg(
        long = "squash",
        value_name = "SOURCE,TARGET",
        value_parser = SquashSpec::parse,
        default_missing_value = "@,@-",
        num_args = 0..=1
    )]
    pub value: Option<SquashSpec>,
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn squash_parse_valid() {
        let sq = SquashSpec::parse("@,@-").unwrap();
        assert_eq!(sq.source, "@");
        assert_eq!(sq.target, "@-");
    }

    #[test]
    fn squash_parse_invalid() {
        assert!(SquashSpec::parse("@").is_err());
        assert!(SquashSpec::parse(",").is_err());
        assert!(SquashSpec::parse("@,").is_err());
        assert!(SquashSpec::parse(",@-").is_err());
    }
}

//! `--dry-run` — show what would be done without executing.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--dry-run` leaf (Flag — boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct DryRunFlag {
    /// Dry run — show what would be done without executing.
    #[arg(long)]
    pub dry_run: bool,
}

//! `--private` — create private repos on the remote provisioner.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--private` leaf (Flag — boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct PrivateFlag {
    /// Create private GitHub repos (default: public).
    ///
    /// - Only meaningful when the resolved provisioner is
    ///   `gh repo create` (GitHub URL or `--repo remote` whose
    ///   value points at GitHub).
    #[arg(long, verbatim_doc_comment)]
    pub private: bool,
}

//! `--account` — selects an account section in the user config.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--account` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct AccountOption {
    /// Account name — picks `[account.<a>]` from user config.
    ///
    /// - Without this flag, `[default].account` (or top-level
    ///   `[repo]` shorthand) is used.
    /// - Meaningful only with Path or bare-NAME targets — URL /
    ///   owner/name targets supply the remote directly.
    #[arg(long, value_name = "NAME", verbatim_doc_comment)]
    pub account: Option<String>,
}

//! `--use-template` — seed repos from template directories.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--use-template` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
#[derive(Args, Debug, Clone, Default)]
pub struct UseTemplateOption {
    /// Seed repos from template directories.
    ///
    /// Value is `CODE[,BOT]`. Default bot path is `<CODE>.claude`
    /// (file-name concat, not path join — templates are siblings).
    ///
    /// - With `--scope=por`: only `CODE` is used; passing `,BOT`
    ///   is fatal (no session side to seed).
    /// - Non-hidden contents copied recursively; hidden entries
    ///   (names starting with `.`) are skipped — init writes its
    ///   own hidden files.
    /// - If a copied tree has a `README.md`, its first line is
    ///   rewritten to `# <repo-name>`.
    #[arg(long, value_name = "CODE[,BOT]", verbatim_doc_comment)]
    pub use_template: Option<String>,
}

//! `--por` — create a plain single repo (no `.claude/` companion).
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--por` leaf (Flag — boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
///
/// Workspace topology selector at creation time:
///
/// - Absent (`--por` not passed) — dual workspace (work +
///   `.claude/` bot repo).
/// - Present (`--por` passed) — plain single repo, no
///   `.claude/`, no `.vc-config.toml`.
#[derive(Args, Debug, Clone, Default)]
pub struct PorFlag {
    /// Create a plain single repo (no `.claude/` companion).
    #[arg(long = "por")]
    pub value: bool,
}

